-- Snapshot seed data for local development/demo.
-- Assumes all migrations have been applied (BIGINT identity PKs).
-- NOTE:
--   - Seeds one primary active photo per product; URLs match files under data/product-photos/products/{id}/.
--   - snapshotdb.py copies data/default-photos/blackpink.jpg to those paths before this SQL runs.
--   - Product brands match ui/src/components/HomePage.tsx BRAND_ORDER (same names, same order).
--   - Uses explicit integer ids compatible with GENERATED BY DEFAULT AS IDENTITY.

BEGIN;

TRUNCATE TABLE
  order_items,
  orders,
  reviews,
  photos,
  products,
  users
RESTART IDENTITY CASCADE;


SELECT setval(pg_get_serial_sequence('users', 'id'), (SELECT COALESCE(MAX(id), 1) FROM users));


SELECT setval(pg_get_serial_sequence('products', 'id'), (SELECT COALESCE(MAX(id), 1) FROM products));


SELECT setval(pg_get_serial_sequence('photos', 'id'), (SELECT COALESCE(MAX(id), 1) FROM photos));


SELECT setval(pg_get_serial_sequence('reviews', 'id'), (SELECT COALESCE(MAX(id), 1) FROM reviews));


SELECT setval(pg_get_serial_sequence('orders', 'id'), (SELECT COALESCE(MAX(id), 1) FROM orders));


SELECT setval(pg_get_serial_sequence('order_items', 'id'), (SELECT COALESCE(MAX(id), 1) FROM order_items));

COMMIT;
